  "phase": "plan",
  "decisions": [
    {
      "id": "d1",
      "decision": "Include ProbabilityEdit.impactScore in cost basis, attributed proportionally across outcomes based on absolute marginal changes. impactScore is liquidity × KL_divergence which is in currency units, making it semantically valid as cost basis alongside EventTrade.notional.",
      "based_on": ["q1"],
      "alternatives_rejected": [
        "Exclude ProbabilityEdit from cost basis — simplifies implementation but loses real economic cost of probability edits, contradicts parent plan decision d2",
        "Attribute full impactScore to single outcome with largest probability increase — arbitrary when multiple outcomes shift"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d2",
      "decision": "Compute P&L at query time by scanning ORDERS dict. No materialized P&L state. EventTrade cost basis = sum of notional (positive for buys, negative for sells). Unrealized P&L = netSize × currentMarginal - costBasis. Realized P&L = netSize × resolutionProbability - costBasis.",
      "based_on": ["q2"],
      "alternatives_rejected": [
        "Add ACCOUNT_PNL projection dict synced on each trade — too invasive for first iteration, requires modifying multiple write paths"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d3",
      "decision": "Return 404 when account has zero orders in the given market (never participated). Return zero values when orders exist but net P&L is zero. This distinguishes 'never traded' from 'traded but broke even'.",
      "based_on": ["q4"],
      "alternatives_rejected": [
        "Always return 404 for zero P&L — incorrectly implies no participation",
        "Always return zero values — can't distinguish 'never traded' from 'zero P&L'"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d4",
      "decision": "Account-level P&L aggregates across ALL markets including resolved ones. Resolved markets contribute realized P&L, active markets contribute unrealized P&L. Gives lifetime performance view.",
      "based_on": ["q5"],
      "alternatives_rejected": [
        "Only active markets — hides historical P&L from resolved markets"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d5",
      "decision": "Response uses camelCase with top-level 'pnl' key and meta wrapper. Per-outcome breakdown nested under 'outcomes' dict keyed by outcomeId. Market-level summary with totals. Consistent with existing endpoint patterns (make_meta, entity+meta).",
      "based_on": ["q3"],
      "alternatives_rejected": [
        "Use 'data' top-level key — less descriptive than 'pnl' for a domain-specific endpoint"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d6",
      "decision": "For integration tests, create trades on an active market, then resolve it to test realized P&L. Also test unrealized P&L on markets that stay active. Do not manually seed ORDERS since m3 starts resolved with empty order history.",
      "based_on": ["q2"],
      "alternatives_rejected": [
        "Manually seed ORDERS dict — couples tests to internal data structures, fragile",
        "Test only against m3 — has no order history, would return 404"
      ],
      "reversibility": "easy"
    }
  ],
  "steps": [
    {
      "step": 1,
      "task": "Add P&L computation core in server.py: (a) compute_orders_pnl(market_id, account_id) that scans ORDERS, accumulates per-outcome net_size and cost_basis from EventTrade.notional and ProbabilityEdit.impactScore (proportional attribution), (b) compute_market_pnl(market_id, account_id) that wraps compute_orders_pnl and calculates current_value/unrealized/realized P&L based on market status (active: use marginals; resolved: use resolutionProbabilities). Place helpers near existing account query functions (~line 2075).",
      "depends_on": []
    },
    {
      "step": 2,
      "task": "Add per-market P&L endpoint handler: get_market_account_pnl(market_id, account_id) that calls compute_market_pnl, serializes response with per-outcome breakdown {outcomeId, netSize, costBasis, currentValue, unrealizedPnl, realizedPnl, totalPnl} and market-level summary {totalCostBasis, totalCurrentValue, totalUnrealizedPnl, totalRealizedPnl, totalPnl}. Returns 404 if market not found or zero orders for account+market. Uses make_meta() for response wrapper.",
      "depends_on": [1]
    },
    {
      "step": 3,
      "task": "Add routing for per-market P&L: in route_request, match len(parts)==6 with parts pattern ['v1','markets',marketId,'accounts',accountId,'pnl']. GET only, 405 for other methods. Insert in the market resource patterns section (~line 4535+).",
      "depends_on": [2]
    },
    {
      "step": 4,
      "task": "Add account-level P&L endpoint handler: get_account_pnl(account_id) that scans all ORDERS for the account, groups by marketId, calls compute_market_pnl for each, returns per-market breakdown list plus account-level summary {totalPnl, totalUnrealizedPnl, totalRealizedPnl, totalCostBasis, totalCurrentValue}. Returns 404 if account has zero orders across all markets.",
      "depends_on": [1]
    },
    {
      "step": 5,
      "task": "Add routing for account-level P&L: in route_request, add 'pnl' to the allowed resources in the account resource pattern (len(parts)==4, parts[3]=='pnl'). GET only. Insert alongside existing risk/exposure/positions routing (~line 4519).",
      "depends_on": [4]
    },
    {
      "step": 6,
      "task": "Integration tests in tests/ directory: (a) Test unrealized P&L — create EventTrade buy orders on active market m1, query per-market P&L, verify costBasis=notional, currentValue=netSize×marginal, unrealizedPnl=currentValue-costBasis. (b) Test realized P&L — create trades on m1 or m2, resolve market, verify realizedPnl uses resolutionProbabilities. (c) Test ProbabilityEdit cost basis — create probability edit, verify impactScore included in costBasis. (d) Test 404 for no orders. (e) Test account-level aggregation across multiple markets. (f) Test sell orders reduce position and cost basis correctly.",
      "depends_on": [3, 5]
    }
  ],
  "spawn_children": false,
  "children": []
}

{
  "phase": "question",
  "questions": [
    {
      "id": "q1",
      "question": "How should ProbabilityEdit orders contribute to cost basis? The impactScore is a KL divergence (information-theoretic measure), not a monetary amount like EventTrade.notional. Should we treat impactScore as a sunk cost in currency units, or only count EventTrade orders for cost basis?",
      "category": "requirements",
      "why_it_matters": "ProbabilityEdit orders don't have a price/size/notional field. If impactScore is treated as cost basis, it mixes units (KL divergence vs. currency). The plan says to use impactScore but this may produce semantically incorrect P&L values."
    },
    {
      "id": "q2",
      "question": "For resolved markets (like m3), positions are removed from ACCOUNT_EXPOSURE during settlement (settle_market_account_exposure). Should realized P&L be reconstructed purely from ORDERS history, and how do we determine what the settlement value was for each position?",
      "category": "design",
      "why_it_matters": "After resolution, positions are pruned from exposure state. We need to reconstruct position history from ORDERS to compute realized P&L. Settlement value depends on whether the account held the winning outcome (value=1.0 per unit) or losing outcome (value=0.0)."
    },
    {
      "id": "q3",
      "question": "What is the expected response schema for the P&L endpoints? Should it return per-outcome breakdown (e.g., separate P&L for 'yes' and 'no' positions) or aggregate per-market? Should it include fields like cost_basis, current_value, unrealized_pnl, realized_pnl, total_pnl?",
      "category": "requirements",
      "why_it_matters": "The plan mentions 'per-market P&L breakdown (unrealized, realized, total, cost_basis, current_value) per outcome' but the exact JSON shape and field naming convention needs to match the existing API style (camelCase vs snake_case)."
    },
    {
      "id": "q4",
      "question": "Should the per-market endpoint (GET /v1/markets/{marketId}/accounts/{accountId}/pnl) return 404 if the account has no orders in that market, or return zero values?",
      "category": "design",
      "why_it_matters": "Existing account endpoints (risk, exposure, positions) return 404 for unknown accounts. Consistency matters, but a 404 vs empty-result choice affects frontend error handling."
    },
    {
      "id": "q5",
      "question": "For the account-level endpoint, should it aggregate across ALL markets (including resolved ones where orders exist in history) or only active markets with live positions?",
      "category": "requirements",
      "why_it_matters": "If we include resolved markets, we show lifetime realized P&L. If only active, we show current unrealized exposure. The plan says 'aggregated across all markets' which suggests both."
    }
  ],
  "assumptions": [
    {
      "id": "a1",
      "assumption": "P&L is computed at query time by scanning ORDERS dict (no materialized/cached P&L state). Cost basis for EventTrade = sum of (notional) for buys, minus sum of (notional) for sells.",
      "confidence": 0.9,
      "if_wrong": "Would need to add a new in-memory projection dict (like ACCOUNT_PNL) and sync it on each trade, similar to ACCOUNT_RISK."
    },
    {
      "id": "a2",
      "assumption": "ProbabilityEdit impactScore IS treated as cost basis (per plan decision d2), despite being a KL divergence value. The system treats it as a 'price paid' for moving the market.",
      "confidence": 0.6,
      "if_wrong": "If impactScore should NOT be cost basis, then only EventTrade orders contribute to P&L, and ProbabilityEdit orders have no P&L impact. This simplifies the implementation significantly."
    },
    {
      "id": "a3",
      "assumption": "Unrealized P&L = (netSize * currentMarginal) - costBasis for active markets. Realized P&L = (netSize * settlementPrice) - costBasis for resolved markets, where settlementPrice is 1.0 for winning outcome and 0.0 for losing outcome.",
      "confidence": 0.85,
      "if_wrong": "Alternative P&L formulas (e.g., FIFO-based, mark-to-market with partial closes) would require more complex order history traversal."
    },
    {
      "id": "a4",
      "assumption": "The route for per-market P&L will be matched as len(parts)==6 with parts pattern ['v1','markets',marketId,'accounts',accountId,'pnl'] in the existing route_request function.",
      "confidence": 0.95,
      "if_wrong": "Minor routing adjustment needed but the path-segment matching pattern is well-established."
    },
    {
      "id": "a5",
      "assumption": "Response fields use camelCase (matching existing API: accountId, marketId, netSize, lastTradePrice, etc.) and include a 'meta' wrapper consistent with other endpoints.",
      "confidence": 0.95,
      "if_wrong": "Just a naming convention change, low risk."
    },
    {
      "id": "a6",
      "assumption": "For resolved markets, we reconstruct the position from ORDERS history (filtering by accountId + marketId, computing net size from buy/sell EventTrade orders) since positions are pruned from ACCOUNT_EXPOSURE on settlement.",
      "confidence": 0.85,
      "if_wrong": "If there's another way to get historical position data for resolved markets, the implementation would be simpler."
    },
    {
      "id": "a7",
      "assumption": "Integration tests (step 9) will use the test helper pattern: call route_request directly, set up trades via event-trade endpoint on market m3 (already resolved) or create new trades on m1/m2 (active), then assert P&L values.",
      "confidence": 0.8,
      "if_wrong": "May need to seed ORDERS manually for resolved market test cases since m3 starts resolved with no order history in the initial state."
    }
  ],
  "spawn_children": false,
  "children": []
}

